entry:
  %sub1 = sub nsw i32 %x, %y
  %sub2 = sub nsw i32 %z, %w
  %sel = select i1 %c, i32 %sub1, i32 %sub2
  %neg = sub i32 0, %sel
  ret i32 %neg
}
```
