### Original IR
```llvm
define ptr @test(i1 %cond, ptr %base, i64 %idx1, i64 %idx2, i64 %idx3) {
entry:
  br i1 %cond, label %if.then, label %if.else

if.then:
  %gep1 = getelementptr inbounds i8, ptr %base, i64 %idx1
  br label %merge

if.else:
  %gep2 = getelementptr i8, ptr %base, i64 %idx2
