  %b = xor i32 %a, -1
  %and = and i32 %a, %b
  %res = xor i32 %and, -1
  ret i32 %res
}
```
### Optimized IR
```llvm
define i32 @test(i1 %cond, i32 %x, i32 %y) {
  %a = select i1 %cond, i32 %y, i32 %x
  ret i32 %a
}
```

