### Original IR
```llvm
define i8 @test(i1 %c) {
  %f = freeze i8 poison
  %s = select i1 %c, i8 %f, i8 %f
  ret i8 %s
}
```
### Optimized IR
```llvm
define i8 @test(i1 %c) {
  ret i8 poison
}
```

