5334   LLVMContext &Ctx = V->getContext();
5335 
5336   // Undef don't care.
5337   auto *UndefInt8 = UndefValue::get(Type::getInt8Ty(Ctx));
5338   if (isa<UndefValue>(V))
5339     return UndefInt8;
