5345   Constant *C = dyn_cast<Constant>(V);
5346   if (!C) {
5347     // Conceptually, we could handle things like:
5348     //   %a = zext i8 %X to i16
5349     //   %b = shl i16 %a, 8
5350     //   %c = or i16 %a, %b
5351     // but until there is an example that actually needs this, it doesn't seem
5352     // worth worrying about.
5353     return nullptr;
5354   }
5355 
5356   // Handle 'null' ConstantArrayZero etc.
5357   if (C->isNullValue())
5358     return Constant::getNullValue(Type::getInt8Ty(Ctx));
