5360   // Constant floating-point values can be handled as integer values if the
5361   // corresponding integer value is "byteable".  An important case is 0.0.
5362   if (ConstantFP *CFP = dyn_cast<ConstantFP>(C)) {
5363     Type *Ty = nullptr;
5364     if (CFP->getType()->isHalfTy())
5365       Ty = Type::getInt16Ty(Ctx);
5366     else if (CFP->getType()->isFloatTy())
5367       Ty = Type::getInt32Ty(Ctx);
5368     else if (CFP->getType()->isDoubleTy())
5369       Ty = Type::getInt64Ty(Ctx);
5370     // Don't handle long double formats, which have strange constraints.
5371     return Ty ? isBytewiseValue(ConstantExpr::getBitCast(CFP, Ty), DL)
5372               : nullptr;
5373   }
5374 
5375   // We can handle constant integers that are multiple of 8 bits.
5376   if (ConstantInt *CI = dyn_cast<ConstantInt>(C)) {
5377     if (CI->getBitWidth() % 8 == 0) {
5378       assert(CI->getBitWidth() > 8 && "8 bits should be handled above!");
5379       if (!CI->getValue().isSplat(8))
5380         return nullptr;
5381       return ConstantInt::get(Ctx, CI->getValue().trunc(8));
5382     }
5383   }
5384 
5385   if (auto *CE = dyn_cast<ConstantExpr>(C)) {
5386     if (CE->getOpcode() == Instruction::IntToPtr) {
5387       if (auto *PtrTy = dyn_cast<PointerType>(CE->getType())) {
5388         unsigned BitWidth = DL.getPointerSizeInBits(PtrTy->getAddressSpace());
5389         if (Constant *Op = ConstantFoldIntegerCast(
5390                 CE->getOperand(0), Type::getIntNTy(Ctx, BitWidth), false, DL))
5391           return isBytewiseValue(Op, DL);
5392       }
5393     }
5394   }
