5428 // This is the recursive version of BuildSubAggregate. It takes a few different
5429 // arguments. Idxs is the index within the nested struct From that we are
5430 // looking at now (which is of type IndexedType). IdxSkip is the number of
5431 // indices from Idxs that should be left out when inserting into the resulting
5432 // struct. To is the result struct built so far, new insertvalue instructions
5433 // build on that.
5434 static Value *BuildSubAggregate(Value *From, Value* To, Type *IndexedType,
5435                                 SmallVectorImpl<unsigned> &Idxs,
5436                                 unsigned IdxSkip,
5437                                 Instruction *InsertBefore) {
5438   StructType *STy = dyn_cast<StructType>(IndexedType);
5439   if (STy) {
5440     // Save the original To argument so we can modify it
5441     Value *OrigTo = To;
5442     // General case, the type indexed by Idxs is a struct
5443     for (unsigned i = 0, e = STy->getNumElements(); i != e; ++i) {
5444       // Process each struct element recursively
5445       Idxs.push_back(i);
5446       Value *PrevTo = To;
5447       To = BuildSubAggregate(From, To, STy->getElementType(i), Idxs, IdxSkip,
5448                              InsertBefore);
5449       Idxs.pop_back();
5450       if (!To) {
5451         // Couldn't find any inserted value for this index? Cleanup
5452         while (PrevTo != OrigTo) {
5453           InsertValueInst* Del = cast<InsertValueInst>(PrevTo);
5454           PrevTo = Del->getAggregateOperand();
5455           Del->eraseFromParent();
5456         }
5457         // Stop processing elements
5458         break;
5459       }
5460     }
5461     // If we successfully found a value for each of our subaggregates
5462     if (To)
5463       return To;
5464   }
5465   // Base case, the type indexed by SourceIdxs is not a struct, or not all of
5466   // the struct's elements had a value that was inserted directly. In the latter
5467   // case, perhaps we can't determine each of the subelements individually, but
5468   // we might be able to find the complete struct somewhere.
5469 
5470   // Find the value that is at that particular spot
5471   Value *V = FindInsertedValue(From, Idxs);
5472 
5473   if (!V)
